#!/usr/bin/env python3
# TurnIt Auth + Input update - run from repo root: python3 decode_auth_input.py
import base64, os

ROOT = "."
def w(p, d):
    f = os.path.join(ROOT, p)
    dd = os.path.dirname(f)
    if dd: os.makedirs(dd, exist_ok=True)
    open(f, "wb").write(base64.b64decode(d))
    print(f"  WROTE  {p}")

print("=== TurnIt Auth + Model Selector ===")

w('app/src/main/java/com/turnit/app/ui/AuthUI.kt', "")
w('app/src/main/java/com/turnit/app/ui/Composables.kt', "")

print()
print("=== DONE: 2 files written ===")
print()
print("Usage:")
print("  LoginScreen(onLoginClick = { u, p -> }, onSignupClick = { })")
print("  SignupScreen(onSignupClick = { u, e, p -> }, onLoginClick = { })")
